% Define the variables
var int: arr[3];

% Generate all possible combinations of three distinct integers from 1 to 5
generate_combinations() {
    for i in 1..5 do
        for j in 1..5 do
            if i != j then
                for k in 1..5 do
                    if j != k and i != k then
                        arr[1] = i;
                        arr[2] = j;
                        arr[3] = k;
                        yield;
                    end if
                end for
            end if
        end for
    end for
}

% Check the sum constraint
check_sum_constraint(arr) {
    return sum(arr) < 10;
}

% Maximize the sum
maximize_sum(arr) {
    return sum(arr);
}

% Main function
solve {
    generate_combinations();
    foreach arr in all_combinations do
        if check_sum_constraint(arr) then
            output show(maximize_sum(arr));
        end if
    end foreach
}

